            "title": "Problem 82",
            "description": "Write a Python program to find the area of a circle. Prompt the user to enter the radius.\nExamples:\n  circle(1) → 3.141592653589793\n  circle(2) → 12.566370614359172",
            "initialCode": "import math\ndef circle():\n    pass\n\ndef calculate_circle_area():\n    pass\n\nimport math\ndef calculate_circle_area(radius):\n    pass\n\ndef main():\n    pass",
            "solution": "import math\n\n# Using function approach\ndef circle():\n    radius = float(input('type number: '))  # e.g., 5.0\n    area = math.pi * radius ** 2  # math.pi \\u00d7 5\\u00b2 = 25\\u03c0 \\u2248 78.54\n    print(area)  # Display the area\ncircle()  # Call the function\ndef calculate_circle_area():\n    radius = float(input('Enter the radius of the circle: '))  # e.g., 10.0\n    area = math.pi * radius ** 2  # \\u03c0 \\u00d7 10\\u00b2 = 100\\u03c0 \\u2248 314.16\n    print(f'The area of the circle with radius {radius} is {area:.2f}')  # Prints: 'The area of the circle with radius 10.0 is 314.16'\ncalculate_circle_area()  # Call the function\nimport math\ndef calculate_circle_area(radius):\n    return math.pi * radius ** 2  # Returns area value\ndef main():\n    radius = float(input('Enter the radius of the circle: '))\n    area = calculate_circle_area(radius)  # Call calculation function\n    print(f'The area of the circle with radius {radius} is {area:.2f}')\nif __name__ == '__main__':\n    main()  # Call main function\n\n# Alternative solution using lambda\ncalculate_circle_area = lambda radius: math.pi * radius ** 2\nprint(f'Area: {calculate_circle_area(7):.2f}')  # Output: Area: 153.94\n\n# Alternative solution with class\nclass Circle:\n    def __init__(self, radius):\n        self.radius = radius\n    def area(self):\n        return math.pi * self.radius ** 2\ncircle = Circle(10)\nprint(f'Area: {circle.area():.2f}')  # Output: Area: 314.16\n\n# Using built-in approach\ndef circle():\n    radius = float(input('type number: '))  # e.g., 5.0\n    area = math.pi * radius ** 2  # math.pi \\u00d7 5\\u00b2 = 25\\u03c0 \\u2248 78.54\n    return area\n\n# Using manual approach\ndef circle():\n    radius = float(input('type number: '))  # e.g., 5.0\n    area = math.pi * radius ** 2  # math.pi \\u00d7 5\\u00b2 = 25\\u03c0 \\u2248 78.54\n    result = area\n    return result\n\n# Script approach\nradius = 7\nresult = calculate_circle_area(radius)\nprint(result)\n\n# Direct approach\nprint(calculate_circle_area(14))",

