            "initialCode": "def sum_of_digits(number):\n    pass",
            "solution": "# Using function approach\ndef sum_of_digits(number):\n    total = 0\n    while number > 0:\n        digit = number % 10  # Get last digit: 5, then 4, then 3, then 2, then 1\n        total += digit  # Add digit to total: 0+5=5, 5+4=9, 9+3=12, 12+2=14, 14+1=15\n        number //= 10  # Remove last digit: 12345\\u21921234\\u2192123\\u219212\\u21921\\u21920\n    return total  # Returns: 15 (sum of digits 1+2+3+4+5)\nnumber = 12345\nresult = sum_of_digits(number)\nprint(f'The sum of the digits of {number} is: {result}')  # Output: 'The sum of the digits of 12345 is: 15'\n\n# Alternative using string conversion\ndef sum_of_digits(number):\n    return sum(int(d) for d in str(abs(number)))\nprint(sum_of_digits(12345))\n\n# Alternative using for loop with string\ndef sum_of_digits(number):\n    total = 0\n    for d in str(abs(number)):\n        total += int(d)\n    return total\nprint(sum_of_digits(12345))\n\n# Alternative using recursive approach\ndef sum_of_digits(number):\n    number = abs(number)\n    if number == 0:\n        return 0\n    return number % 10 + sum_of_digits(number // 10)\nprint(sum_of_digits(12345))\n\n# Using built-in approach\ndef sum_of_digits(number):\n    result = total\n    return result\n\n# Using manual approach\ndef sum_of_digits(number):\n    return total\n\n# Script approach\nnumber = 15\nresult = sum_of_digits(number)\nprint(result)\n\n# Direct approach\nprint(sum_of_digits(25))",

