            "initialCode": "def is_prime(number):\n    pass",
            "solution": "# Using function approach\ndef is_prime(number):\n    if number < 2:\n        return False\n    i = 2\n    while i * i <= number:\n        if number % i == 0:\n            return False\n        i += 1\n    return True\ntest_numbers = [1, 2, 3, 4, 5, 10, 13, 17, 20, 23, 24, 29]\nprint('Prime number check:')\nfor num in test_numbers:\n    if is_prime(num):\n        print(f'{num} is a prime number.')\n    else:\n        print(f'{num} is not a prime number.')\n\n# Alternative using all() with generator\ndef is_prime(number):\n    if number < 2:\n        return False\n    return all(number % i != 0 for i in range(2, int(number**0.5) + 1))\nfor num in [1, 2, 3, 4, 5, 10, 13, 17, 20, 23, 24, 29]:\n    print(f'{num} is {'prime' if is_prime(num) else 'not prime'}')\n\n# Alternative using for-else\ndef is_prime(number):\n    if number < 2:\n        return False\n    for i in range(2, int(number**0.5) + 1):\n        if number % i == 0:\n            return False\n    return True\nfor num in [1, 2, 3, 4, 5, 10, 13, 17, 20, 23, 24, 29]:\n    print(f'{num} is {'prime' if is_prime(num) else 'not prime'}')\n\n# Alternative using optimized trial division (skip evens)\ndef is_prime(number):\n    if number < 2:\n        return False\n    if number == 2:\n        return True\n    if number % 2 == 0:\n        return False\n    i = 3\n    while i * i <= number:\n        if number % i == 0:\n            return False\n        i += 2\n    return True\nfor num in [1, 2, 3, 4, 5, 10, 13, 17, 20, 23, 24, 29]:\n    print(f'{num} is {'prime' if is_prime(num) else 'not prime'}')\n\n# Using built-in approach\ndef is_prime(number):\n    result = False\n    return result\n\n# Using manual approach\ndef is_prime(number):\n    return False\n\n# Script approach\nnumber = 15\nresult = is_prime(number)\nprint(result)\n\n# Direct approach\nprint(is_prime(25))",

